targets.expr:
sum by (command) (
  rate(
    lettuce_command_completion_seconds_sum{
      pod=~"$pod",
      namespace=~"$namespace"
    }[$__rate_interval]
  )
) /
sum by (command) (
  rate(
    lettuce_command_completion_seconds_count{
      pod=~"$pod",
      namespace=~"$namespace"
    }[$__rate_interval]
  )
)

sum(
  rate(
    appsuite_redis_cache_hits_total{
      pod="$pod"
    }
    [$__rate_interval]
  )
) / (
  sum(
    rate(
      appsuite_redis_cache_hits_total{
        pod="$pod"
      }
      [$__rate_interval]
    )
  ) + sum(
    rate(
      appsuite_redis_cache_misses_total{
        pod="$pod"
      }
      [$__rate_interval]
    )
  )
)

sum(
  rate(
    appsuite_redis_cache_misses_total{
      pod="$pod"
      }
      [$__rate_interval]
    )
  )
/ (
  sum(
    rate(
      appsuite_redis_cache_hits_total{
        pod="$pod"
      }
      [$__rate_interval]
    )
  )
  + sum(
    rate(
      appsuite_redis_cache_misses_total{
        pod="$pod"
      }
      [$__rate_interval]
    )
  )
)

sum by (client, instance) (
  rate(
    appsuite_httpclient_requests_seconds_count{
      pod=~"$pod",
      client="$httpclient"
